import { createContext, useContext } from 'react';

import type { ExternalConfig } from '../types.js';

export const ExternalConfigContext = createContext({
  defaultActionsConfig: new Map(),
} as ExternalConfig);

export const useExternalConfig = () => {
  const config = useContext(ExternalConfigContext);

  if (!config) {
    throw new Error('config not used within ConfigContext provider.');
  }

  return config;
};
